import { describe, it, expect, beforeEach, afterEach } from 'vitest'
import {
  mkdtempSync,
  mkdirSync,
  writeFileSync,
  readFileSync,
  rmSync,
  existsSync,
  readdirSync,
} from 'node:fs'
import { join } from 'node:path'
import { tmpdir } from 'node:os'
import { buildReport, ensureGitignore, parseMessagesFromMarkdown } from '../../src/build.js'

// ---------------------------------------------------------------------------
// Setup
// ---------------------------------------------------------------------------

let tmpDir: string

beforeEach(() => {
  tmpDir = mkdtempSync(join(tmpdir(), 'build-test-'))
  delete process.env['ANTHROPIC_API_KEY']
})

afterEach(() => {
  rmSync(tmpDir, { recursive: true, force: true })
  delete process.env['ANTHROPIC_API_KEY']
})

// ---------------------------------------------------------------------------
// ensureGitignore
// ---------------------------------------------------------------------------

describe('ensureGitignore', () => {
  it('creates .gitignore with entry if missing', () => {
    ensureGitignore(tmpDir, 'Memory/07_reports/')
    const path = join(tmpDir, '.gitignore')
    expect(existsSync(path)).toBe(true)
    const content = readFileSync(path, 'utf-8')
    expect(content).toContain('Memory/07_reports/')
  })

  it('appends to existing .gitignore', () => {
    const path = join(tmpDir, '.gitignore')
    writeFileSync(path, 'node_modules/\ndist/\n', 'utf-8')
    ensureGitignore(tmpDir, 'Memory/07_reports/')
    const content = readFileSync(path, 'utf-8')
    expect(content).toContain('node_modules/')
    expect(content).toContain('Memory/07_reports/')
  })

  it('does not add duplicate entry', () => {
    const path = join(tmpDir, '.gitignore')
    writeFileSync(path, 'Memory/07_reports/\n', 'utf-8')
    ensureGitignore(tmpDir, 'Memory/07_reports/')
    const content = readFileSync(path, 'utf-8')
    const count = (content.match(/Memory\/07_reports\//g) ?? []).length
    expect(count).toBe(1)
  })
})

// ---------------------------------------------------------------------------
// parseMessagesFromMarkdown
// ---------------------------------------------------------------------------

describe('parseMessagesFromMarkdown', () => {
  it('parses messages from clean markdown format', () => {
    const md = `---
client: codex
---

# Test Session

## Messages

### 1. user
- Timestamp: \`2026-03-10T10:00:00Z\`

Hello, how are you?

### 2. assistant
- Timestamp: \`2026-03-10T10:00:05Z\`

I'm doing well, thank you!
`
    const messages = parseMessagesFromMarkdown(md)
    expect(messages).toHaveLength(2)
    expect(messages[0]!.role).toBe('user')
    expect(messages[0]!.text).toContain('Hello')
    expect(messages[1]!.role).toBe('assistant')
    expect(messages[1]!.text).toContain("I'm doing well")
  })

  it('returns empty array when no ## Messages section', () => {
    const md = '# Title\n\nSome content.'
    expect(parseMessagesFromMarkdown(md)).toEqual([])
  })

  it('parses timestamps', () => {
    const md = `\n## Messages\n\n### 1. user\n- Timestamp: \`2026-03-10T10:00:00Z\`\n\nHello`
    const messages = parseMessagesFromMarkdown(md)
    expect(messages[0]!.timestamp).toBe('2026-03-10T10:00:00Z')
  })
})

// ---------------------------------------------------------------------------
// buildReport integration test
// ---------------------------------------------------------------------------

describe('buildReport', () => {
  function scaffoldMemory(root: string): void {
    // Create directory structure
    const manifestsDir = join(root, 'Memory', '06_transcripts', 'manifests', 'codex', '2026', '03')
    const cleanDir = join(root, 'Memory', '06_transcripts', 'clean', 'codex', '2026', '03')
    mkdirSync(manifestsDir, { recursive: true })
    mkdirSync(cleanDir, { recursive: true })

    const stem = 'test-session__deadbeef'
    const manifest = {
      client: 'codex',
      project: 'test',
      session_id: 'test-session-001',
      raw_sha256: 'deadbeef' + '0'.repeat(56),
      title: 'Integration Test Session',
      started_at: '2026-03-10T10:00:00Z',
      imported_at: '2026-03-10T10:01:00Z',
      cwd: '/home/user/project',
      branch: 'main',
      raw_source_path: '/src/session.jsonl',
      raw_upload_permission: 'not-set',
      global_raw_path: '',
      global_clean_path: '',
      global_manifest_path: '',
      repo_raw_path: '',
      repo_clean_path: `Memory/06_transcripts/clean/codex/2026/03/${stem}.md`,
      repo_manifest_path: `Memory/06_transcripts/manifests/codex/2026/03/${stem}.json`,
      message_count: 2,
      tool_event_count: 0,
      cleaning_mode: 'deterministic-code',
      repo_mirror_enabled: true,
    }

    writeFileSync(
      join(manifestsDir, `${stem}.json`),
      JSON.stringify(manifest, null, 2),
      'utf-8',
    )

    const cleanMd = `---
client: codex
---

# Integration Test Session

## Messages

### 1. user
- Timestamp: \`2026-03-10T10:00:00Z\`

Build the report system.

### 2. assistant
- Timestamp: \`2026-03-10T10:00:05Z\`

I'll help with that!
`
    writeFileSync(join(cleanDir, `${stem}.md`), cleanMd, 'utf-8')
  }

  it('creates all expected HTML files', async () => {
    scaffoldMemory(tmpDir)
    const output = join(tmpDir, 'Memory', '07_reports')

    await buildReport({
      root: tmpDir,
      output,
      noAi: true,
    })

    expect(existsSync(join(output, 'index.html'))).toBe(true)
    expect(existsSync(join(output, 'transcripts', 'index.html'))).toBe(true)
    expect(existsSync(join(output, 'goals', 'index.html'))).toBe(true)
    expect(existsSync(join(output, 'knowledge', 'index.html'))).toBe(true)
    expect(existsSync(join(output, 'search.html'))).toBe(true)
  })

  it('generates individual transcript HTML with SVG charts in dashboard', async () => {
    scaffoldMemory(tmpDir)
    const output = join(tmpDir, 'Memory', '07_reports')

    await buildReport({ root: tmpDir, output, noAi: true })

    // Dashboard should contain SVG
    const dashHtml = readFileSync(join(output, 'index.html'), 'utf-8')
    expect(dashHtml).toContain('<svg')

    // Individual transcript should exist
    const transcriptDir = join(output, 'transcripts', 'codex')
    expect(existsSync(transcriptDir)).toBe(true)
    const files = readdirSync(transcriptDir)
    expect(files.some(f => f.endsWith('.html'))).toBe(true)
  })

  it('creates .gitignore entry for Memory/07_reports/', async () => {
    scaffoldMemory(tmpDir)
    const output = join(tmpDir, 'Memory', '07_reports')

    await buildReport({ root: tmpDir, output, noAi: true })

    const gitignore = readFileSync(join(tmpDir, '.gitignore'), 'utf-8')
    expect(gitignore).toContain('Memory/07_reports/')
  })

  it('removes stale generated files before rebuilding', async () => {
    scaffoldMemory(tmpDir)
    const output = join(tmpDir, 'Memory', '07_reports')
    const stalePath = join(output, 'transcripts', 'codex', 'stale.html')

    mkdirSync(join(output, 'transcripts', 'codex'), { recursive: true })
    writeFileSync(stalePath, '<html>stale</html>', 'utf-8')

    await buildReport({ root: tmpDir, output, noAi: true })

    expect(existsSync(stalePath)).toBe(false)
  })

  it('scopes duplicate heading anchors per markdown file', async () => {
    scaffoldMemory(tmpDir)
    const goalsDir = join(tmpDir, 'Memory', '01_goals')
    mkdirSync(goalsDir, { recursive: true })
    writeFileSync(join(goalsDir, 'a.md'), '# Goal A\n\n## Overview\n\nAlpha\n', 'utf-8')
    writeFileSync(join(goalsDir, 'b.md'), '# Goal B\n\n## Overview\n\nBeta\n', 'utf-8')
    const output = join(tmpDir, 'Memory', '07_reports')

    await buildReport({ root: tmpDir, output, noAi: true })

    const html = readFileSync(join(output, 'goals', 'index.html'), 'utf-8')
    expect(html).toContain('href="#a-md-overview"')
    expect(html).toContain('href="#b-md-overview"')
    expect((html.match(/id="a-md-overview"/g) ?? [])).toHaveLength(1)
    expect((html.match(/id="b-md-overview"/g) ?? [])).toHaveLength(1)
  })

  it('handles empty Memory directory gracefully', async () => {
    // Create root but no transcripts
    mkdirSync(join(tmpDir, 'Memory'), { recursive: true })
    const output = join(tmpDir, 'Memory', '07_reports')

    await expect(
      buildReport({ root: tmpDir, output, noAi: true }),
    ).resolves.toBeUndefined()

    expect(existsSync(join(output, 'index.html'))).toBe(true)
  })
})

import { describe, it, expect } from 'vitest'
import type { ManifestEntry } from '@openmnemo/types'
import {
  computeStats,
  buildDayBuckets,
  buildWeekBuckets,
  extractToolNames,
  accumulateToolCounts,
} from '../../src/stats.js'

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function makeManifest(overrides: Partial<ManifestEntry> = {}): ManifestEntry {
  return {
    client: 'codex',
    project: 'test',
    session_id: 'abc-123',
    raw_sha256: 'deadbeef',
    title: 'Test Session',
    started_at: '2026-03-10T10:00:00Z',
    imported_at: '2026-03-10T10:01:00Z',
    cwd: '/home/user',
    branch: 'main',
    raw_source_path: '/src/file.jsonl',
    raw_upload_permission: 'not-set',
    global_raw_path: '',
    global_clean_path: '',
    global_manifest_path: '',
    repo_raw_path: '',
    repo_clean_path: '',
    repo_manifest_path: '',
    message_count: 10,
    tool_event_count: 5,
    cleaning_mode: 'deterministic-code',
    repo_mirror_enabled: true,
    ...overrides,
  }
}

// ---------------------------------------------------------------------------
// computeStats
// ---------------------------------------------------------------------------

describe('computeStats', () => {
  it('handles zero manifests', () => {
    const stats = computeStats([])
    expect(stats.totalSessions).toBe(0)
    expect(stats.totalMessages).toBe(0)
    expect(stats.totalToolEvents).toBe(0)
    expect(stats.activeDays).toBe(0)
    expect(stats.dateRange.from).toBe('')
    expect(stats.dateRange.to).toBe('')
    expect(stats.clientCounts).toEqual({})
    expect(stats.dayBuckets).toEqual({})
    expect(stats.weekBuckets).toEqual({})
    expect(stats.toolCounts).toEqual({})
  })

  it('sums messages and tool events', () => {
    const m1 = makeManifest({ message_count: 10, tool_event_count: 5 })
    const m2 = makeManifest({ session_id: 'xyz', message_count: 20, tool_event_count: 3 })
    const stats = computeStats([m1, m2])
    expect(stats.totalSessions).toBe(2)
    expect(stats.totalMessages).toBe(30)
    expect(stats.totalToolEvents).toBe(8)
  })

  it('counts client distribution', () => {
    const m1 = makeManifest({ client: 'codex' })
    const m2 = makeManifest({ session_id: 'b', client: 'claude' })
    const m3 = makeManifest({ session_id: 'c', client: 'claude' })
    const stats = computeStats([m1, m2, m3])
    expect(stats.clientCounts['codex']).toBe(1)
    expect(stats.clientCounts['claude']).toBe(2)
  })

  it('counts active days correctly', () => {
    const m1 = makeManifest({ started_at: '2026-03-10T10:00:00Z' })
    const m2 = makeManifest({ session_id: 'b', started_at: '2026-03-10T14:00:00Z' }) // same day
    const m3 = makeManifest({ session_id: 'c', started_at: '2026-03-11T08:00:00Z' }) // different day
    const stats = computeStats([m1, m2, m3])
    expect(stats.activeDays).toBe(2)
  })

  it('computes date range', () => {
    const m1 = makeManifest({ started_at: '2026-01-01T00:00:00Z' })
    const m2 = makeManifest({ session_id: 'b', started_at: '2026-03-15T00:00:00Z' })
    const stats = computeStats([m1, m2])
    expect(stats.dateRange.from).toBe('2026-01-01T00:00:00Z')
    expect(stats.dateRange.to).toBe('2026-03-15T00:00:00Z')
  })

  it('accepts external toolCounts', () => {
    const stats = computeStats([], { Bash: 10, Read: 5 })
    expect(stats.toolCounts['Bash']).toBe(10)
    expect(stats.toolCounts['Read']).toBe(5)
  })
})

// ---------------------------------------------------------------------------
// buildDayBuckets
// ---------------------------------------------------------------------------

describe('buildDayBuckets', () => {
  it('returns empty for zero manifests', () => {
    expect(buildDayBuckets([])).toEqual({})
  })

  it('buckets sessions by date', () => {
    const m1 = makeManifest({ started_at: '2026-03-10T10:00:00Z' })
    const m2 = makeManifest({ session_id: 'b', started_at: '2026-03-10T14:00:00Z' })
    const m3 = makeManifest({ session_id: 'c', started_at: '2026-03-11T08:00:00Z' })
    const buckets = buildDayBuckets([m1, m2, m3])
    expect(buckets['2026-03-10']).toBe(2)
    expect(buckets['2026-03-11']).toBe(1)
  })

  it('ignores manifests with empty started_at', () => {
    const m = makeManifest({ started_at: '' })
    expect(buildDayBuckets([m])).toEqual({})
  })
})

// ---------------------------------------------------------------------------
// buildWeekBuckets
// ---------------------------------------------------------------------------

describe('buildWeekBuckets', () => {
  it('returns empty for zero manifests', () => {
    expect(buildWeekBuckets([])).toEqual({})
  })

  it('buckets messages by ISO week', () => {
    // 2026-03-10 is in week 2026-W11
    const m1 = makeManifest({ started_at: '2026-03-10T10:00:00Z', message_count: 5 })
    const m2 = makeManifest({ session_id: 'b', started_at: '2026-03-11T10:00:00Z', message_count: 3 })
    const buckets = buildWeekBuckets([m1, m2])
    // Both are in the same week
    const weekKey = Object.keys(buckets)[0]
    expect(weekKey).toMatch(/^\d{4}-W\d{2}$/)
    const val = weekKey ? buckets[weekKey] : 0
    expect(val).toBe(8)
  })
})

// ---------------------------------------------------------------------------
// extractToolNames
// ---------------------------------------------------------------------------

describe('extractToolNames', () => {
  it('extracts first word as tool name', () => {
    const names = extractToolNames(['Bash input={"command":"ls"}', 'Read /file.ts'])
    expect(names[0]).toBe('Bash')
    expect(names[1]).toBe('Read')
  })

  it('handles underscore and hyphen in names', () => {
    const names = extractToolNames(['function_call input=...', 'custom-tool arg=1'])
    expect(names[0]).toBe('function_call')
    expect(names[1]).toBe('custom-tool')
  })

  it('returns unknown for non-identifier start', () => {
    const names = extractToolNames(['123abc', '!cmd'])
    expect(names[0]).toBe('unknown')
    expect(names[1]).toBe('unknown')
  })

  it('handles empty array', () => {
    expect(extractToolNames([])).toEqual([])
  })

  it('handles empty string entries', () => {
    const names = extractToolNames([''])
    expect(names[0]).toBe('unknown')
  })
})

// ---------------------------------------------------------------------------
// accumulateToolCounts
// ---------------------------------------------------------------------------

describe('accumulateToolCounts', () => {
  it('accumulates counts into new map', () => {
    const base = { Bash: 3 }
    const result = accumulateToolCounts(base, ['Bash', 'Read', 'Bash'])
    expect(result['Bash']).toBe(5)
    expect(result['Read']).toBe(1)
  })

  it('does not mutate input', () => {
    const base = { Bash: 1 }
    accumulateToolCounts(base, ['Bash'])
    expect(base['Bash']).toBe(1)
  })
})

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest'
import { mkdtempSync, rmSync, existsSync } from 'node:fs'
import { join } from 'node:path'
import { tmpdir } from 'node:os'
import {
  buildSummaryPrompt,
  readCache,
  writeCache,
  getSummary,
} from '../../src/summarize.js'
import type { SummaryMessage } from '../../src/summarize.js'

// ---------------------------------------------------------------------------
// Setup
// ---------------------------------------------------------------------------

let tmpDir: string

beforeEach(() => {
  tmpDir = mkdtempSync(join(tmpdir(), 'summarize-test-'))
  // Ensure ANTHROPIC_API_KEY is not set for most tests
  delete process.env['ANTHROPIC_API_KEY']
})

afterEach(() => {
  rmSync(tmpDir, { recursive: true, force: true })
  delete process.env['ANTHROPIC_API_KEY']
  vi.restoreAllMocks()
})

// ---------------------------------------------------------------------------
// buildSummaryPrompt
// ---------------------------------------------------------------------------

describe('buildSummaryPrompt', () => {
  it('includes role and text for each message', () => {
    const msgs: SummaryMessage[] = [
      { role: 'user', text: 'Hello world' },
      { role: 'assistant', text: 'Hi there' },
    ]
    const prompt = buildSummaryPrompt(msgs)
    expect(prompt).toContain('USER: Hello world')
    expect(prompt).toContain('ASSISTANT: Hi there')
  })

  it('truncates message text to 500 chars', () => {
    const longText = 'x'.repeat(600)
    const msgs: SummaryMessage[] = [{ role: 'user', text: longText }]
    const prompt = buildSummaryPrompt(msgs)
    const line = prompt.split('\n')[0] ?? ''
    // "USER: " + 500 chars = 506 chars max
    expect(line.length).toBeLessThanOrEqual(506)
  })

  it('limits to first 30 messages', () => {
    const msgs: SummaryMessage[] = Array.from({ length: 50 }, (_, i) => ({
      role: i % 2 === 0 ? 'user' : 'assistant',
      text: `Message ${i}`,
    }))
    const prompt = buildSummaryPrompt(msgs)
    // Prompt should not contain message 30+
    expect(prompt).not.toContain('Message 30')
    expect(prompt).toContain('Message 29')
  })

  it('handles empty messages array', () => {
    const prompt = buildSummaryPrompt([])
    expect(prompt).toBe('')
  })
})

// ---------------------------------------------------------------------------
// Cache read/write
// ---------------------------------------------------------------------------

describe('readCache / writeCache', () => {
  it('returns null for cache miss', () => {
    const result = readCache('nonexistent-sha256', tmpDir)
    expect(result).toBeNull()
  })

  it('round-trips: write then read', () => {
    writeCache('abc123', 'Great session summary.', tmpDir)
    const result = readCache('abc123', tmpDir)
    expect(result).toBe('Great session summary.')
  })

  it('creates cache file at correct path', () => {
    writeCache('sha256abc', 'some summary', tmpDir)
    expect(existsSync(join(tmpDir, 'sha256abc.json'))).toBe(true)
  })

  it('returns null for corrupted cache file', async () => {
    const { writeFileSync } = await import('node:fs')
    writeFileSync(join(tmpDir, 'bad.json'), 'not json!!!', 'utf-8')
    expect(readCache('bad', tmpDir)).toBeNull()
  })
})

// ---------------------------------------------------------------------------
// getSummary
// ---------------------------------------------------------------------------

describe('getSummary', () => {
  it('returns cached summary without API call', async () => {
    writeCache('cachedhash', 'Cached result', tmpDir)
    const result = await getSummary('cachedhash', [], {
      cacheDir: tmpDir,
      noAi: false,
      model: 'claude-haiku-4-5-20251001',
    })
    expect(result).toBe('Cached result')
  })

  it('returns empty string when noAi=true', async () => {
    const result = await getSummary('newsha', [], {
      cacheDir: tmpDir,
      noAi: true,
      model: 'claude-haiku-4-5-20251001',
    })
    expect(result).toBe('')
  })

  it('returns empty string when ANTHROPIC_API_KEY not set', async () => {
    delete process.env['ANTHROPIC_API_KEY']
    const result = await getSummary('newsha2', [], {
      cacheDir: tmpDir,
      noAi: false,
      model: 'claude-haiku-4-5-20251001',
    })
    expect(result).toBe('')
  })

  it('prefers cache over API even when key is set', async () => {
    process.env['ANTHROPIC_API_KEY'] = 'sk-test-key'
    writeCache('cachedwithkey', 'Cached!', tmpDir)
    const result = await getSummary('cachedwithkey', [], {
      cacheDir: tmpDir,
      noAi: false,
      model: 'claude-haiku-4-5-20251001',
    })
    expect(result).toBe('Cached!')
  })
})

import { describe, it, expect } from 'vitest'
import os from 'node:os'
import { join } from 'node:path'
import { mkdirSync, writeFileSync } from 'node:fs'

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function makeTmpDir(): string {
  const dir = join(os.tmpdir(), `mt-tags-test-${Math.random().toString(36).slice(2)}`)
  mkdirSync(dir, { recursive: true })
  return dir
}

// ---------------------------------------------------------------------------
// renderTagBadges tests (synchronous, no AI)
// ---------------------------------------------------------------------------

import { renderTagBadges } from '../../src/tags.js'

describe('renderTagBadges', () => {
  it('returns empty string for empty tags', () => {
    expect(renderTagBadges([])).toBe('')
  })

  it('renders tag pills', () => {
    const html = renderTagBadges(['typescript', 'testing'])
    expect(html).toContain('class="tag"')
    expect(html).toContain('typescript')
    expect(html).toContain('testing')
  })

  it('escapes HTML special chars in tags', () => {
    const html = renderTagBadges(['a&b', '<test>'])
    expect(html).toContain('a&amp;b')
    expect(html).toContain('&lt;test&gt;')
    expect(html).not.toContain('<test>')
  })

  it('sets data-tag attribute', () => {
    const html = renderTagBadges(['typescript'])
    expect(html).toContain('data-tag="typescript"')
  })
})

// ---------------------------------------------------------------------------
// getTags tests
// ---------------------------------------------------------------------------

import { getTags } from '../../src/tags.js'

describe('getTags', () => {
  it('returns [] when noAi=true', async () => {
    const cacheDir = makeTmpDir()
    const result = await getTags('abc123', 'some summary', { cacheDir, noAi: true, model: 'test' })
    expect(result).toEqual([])
  })

  it('returns [] when summary is empty', async () => {
    const cacheDir = makeTmpDir()
    const result = await getTags('abc123', '', { cacheDir, noAi: false, model: 'test' })
    expect(result).toEqual([])
  })

  it('returns [] when summary is whitespace only', async () => {
    const cacheDir = makeTmpDir()
    const result = await getTags('abc123', '   \n  ', { cacheDir, noAi: false, model: 'test' })
    expect(result).toEqual([])
  })

  it('returns [] when no API key set', async () => {
    const cacheDir = makeTmpDir()
    const saved = process.env['ANTHROPIC_API_KEY']
    delete process.env['ANTHROPIC_API_KEY']
    try {
      const result = await getTags('abc123', 'a valid summary', { cacheDir, noAi: false, model: 'test' })
      expect(result).toEqual([])
    } finally {
      if (saved !== undefined) process.env['ANTHROPIC_API_KEY'] = saved
    }
  })

  it('returns cached tags without calling API', async () => {
    const cacheDir = makeTmpDir()
    const sha256 = 'cached-sha256'
    // Write cache file
    const tagsDir = join(cacheDir, 'tags')
    mkdirSync(tagsDir, { recursive: true })
    writeFileSync(
      join(tagsDir, `${sha256}.json`),
      JSON.stringify({ sha256, tags: ['cached', 'tag'], generated_at: '2026-01-01T00:00:00Z' }),
    )
    // Even with a fake API key, cached result should be returned immediately
    const saved = process.env['ANTHROPIC_API_KEY']
    process.env['ANTHROPIC_API_KEY'] = 'fake-key'
    try {
      const result = await getTags(sha256, 'some summary', { cacheDir, noAi: false, model: 'test' })
      expect(result).toEqual(['cached', 'tag'])
    } finally {
      if (saved !== undefined) process.env['ANTHROPIC_API_KEY'] = saved
      else delete process.env['ANTHROPIC_API_KEY']
    }
  })
})

import { describe, it, expect } from 'vitest'
import { loadLocale } from '../../src/i18n/index.js'
import { en } from '../../src/i18n/en.js'
import { zhCN } from '../../src/i18n/zh-CN.js'
import type { Translations } from '../../src/i18n/types.js'

// ---------------------------------------------------------------------------
// Helper: all keys must be defined
// ---------------------------------------------------------------------------

function hasAllKeys(obj: Translations): boolean {
  return (
    typeof obj.nav.dashboard === 'string' &&
    typeof obj.nav.sessions === 'string' &&
    typeof obj.nav.projects === 'string' &&
    typeof obj.nav.graph === 'string' &&
    typeof obj.nav.goals === 'string' &&
    typeof obj.nav.todos === 'string' &&
    typeof obj.nav.knowledge === 'string' &&
